-- =====================================================================-- 0011_pre_flight.sql-- Renames idempotentes, novas colunas, tabela comments.-- =====================================================================-- Renames para nomes definitivos (no-op se já estiverem renomeados).do $$begin  if to_regclass('public.assessment_templates') is not null     and to_regclass('public.templates') is null then    alter table public.assessment_templates rename to templates;  end if;  if to_regclass('public.assessment_cycles') is not null     and to_regclass('public.cycles') is null then    alter table public.assessment_cycles rename to cycles;  end if;  if to_regclass('public.rater_assignments') is not null     and to_regclass('public.assignments') is null then    alter table public.rater_assignments rename to assignments;  end if;end$$;-- tenant_memberships.statusalter table public.tenant_memberships  add column if not exists status text not null default 'active';do $$begin  if not exists (    select 1 from pg_constraint    where conname = 'tenant_memberships_status_check'  ) then    alter table public.tenant_memberships      add constraint tenant_memberships_status_check      check (status in ('active','invited','suspended','revoked'));  end if;end$$;-- people.user_id (vínculo opcional pessoa <-> auth user)alter table public.people  add column if not exists user_id uuid references public.users(id) on delete set null;create unique index if not exists people_tenant_user_uniq  on public.people (tenant_id, user_id) where user_id is not null;-- cycles.allow_admin_raw_readalter table public.cycles  add column if not exists allow_admin_raw_read boolean not null default false;-- comments (qualitativo anônimo, gravado pela RPC submit_response)create table if not exists public.comments (  id uuid primary key default gen_random_uuid(),  tenant_id uuid not null references public.tenants(id) on delete cascade,  assignment_id uuid not null references public.assignments(id) on delete cascade,  question_id uuid references public.questions(id),  body text not null,  created_at timestamptz not null default now());create index if not exists comments_tenant_assignment_idx  on public.comments (tenant_id, assignment_id);alter table public.comments enable row level security;